if("{{shippingCost}}" == "Free shipping"){
    shippingCost = 0.00;
}else{ shippingCost = "{{shippingCost}}".slice(1)};
shippingCost = parseFloat(shippingCost);
let subTotal = "{{subTotal}}";
let subtotalPrice = "{{subtotalPrice}}";

subTotal = subTotal.length ? parseFloat(subTotal) : parseFloat(subtotalPrice);
console.log('Subtotal: ', subTotal);
let taxCost = "{{taxCost}}".slice(1);
taxCost = parseFloat(taxCost);
let total = subTotal + shippingCost + taxCost - {{bulkDiscount}}
return total;
